package com.forloop;
import java .util.*;
public class Squarebtwn1to20
{
	public static void square(int no)
	{
		for(int i=1;i<=no;i++)
		{
			int square=i*i;
			System.out.println("Square of: " +i+ "="+square);

		}
	}

	public static void main(String[] args) 
	{
		// TODO Auto-generated method stub
		square(20);
		
		


	}

}